import React from 'react';
import './skills.css';
import { motion } from 'framer-motion';
import SemiDonutChart from './SemiDonutChart';

const Skills = () => {
  const languages = [
    { txt: "HTML", percentage: 80 },
    { txt: "CSS", percentage: 70 },
    { txt: "JavaScript", percentage: 65 },
    { txt: "React JS", percentage: 75 },
    { txt: "C", percentage: 60 },
    { txt: "C++", percentage: 60 },
    { txt: "Python", percentage: 70 },
  ];

  const libraries = [
    { txt: "NumPy", percentage: 60 },
    { txt: "Pandas", percentage: 55 },
    { txt: "Matplotlib", percentage: 50 },
    { txt: "Python", percentage: 70 },
  ];

  return (
    <motion.div 
      className="skills-container"
      initial={{ opacity: 0, y: 40 }}
      whileInView={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.6 }}
      viewport={{ once: true }}
    >
      <h2 className="main-title">My Skills</h2>

      <div className="skill-section">
        <h3 className="sub-title">Languages</h3>
        <div className="skill-grid">
          {languages.map((skill, i) => (
            <motion.div className="skill-item" key={i} whileHover={{ scale: 1.05 }}>
              <SemiDonutChart {...skill} fill="#6c63ff" />
              <p>{skill.txt}</p>
            </motion.div>
          ))}
        </div>
      </div>

      <div className="skill-section">
        <h3 className="sub-title">Libraries</h3>
        <div className="skill-grid">
          {libraries.map((skill, i) => (
            <motion.div className="skill-item" key={i} whileHover={{ scale: 1.05 }}>
              <SemiDonutChart {...skill} fill="#f67280" />
              <p>{skill.txt}</p>
            </motion.div>
          ))}
        </div>
      </div>
    </motion.div>
  );
};

export default Skills;
